#include<bits/stdc++.h>
using namespace std;
const int maxn=1005;
int n,ans,x=1000000000,y2=1000000000;
struct Node {
	int y,x1,x2;
} a[maxn];
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=1; i<=n; i++) {
		cin>>a[i].y>>a[i].x1>>a[i].x2;
	}
	for(int i=1; i<=n; i++) {
		x=1000000005,y2=1000000005;
		for(int j=1; j<=n; j++) {
			if(i==j) {
				continue;
			}
			if(a[i].x1>=a[j].x1&&a[i].x1<a[j].x2&&a[i].y>a[j].y) {
				x=min(x,a[i].y-a[j].y);
			}
			if(a[i].x2<=a[j].x2&&a[i].x2>a[j].x1&&a[i].y>a[j].y) {
				y2=min(y2,a[i].y-a[j].y);
			}
		}
		ans+=min(x+y2,min(y2+a[i].y,min(x+a[i].y,2*a[i].y)));
	}
	cout<<ans;
	return  0;
}
